package be.schaubroeck.lpb.rkm.rekenmotor.service;

import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenFeedback;
import be.schaubroeck.lpb.tools.Admin;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Persoon;
import be.schaubroeck.lpb.tools.RegulAgenda;
import be.schaubroeck.lpb.tools.RekenLog2;
import be.schaubroeck.lpb.tools.Werkgever;
import be.schaubroeck.lpb.tools.enumtypes.BronAgenda;
import be.schaubroeck.lpb.tools.enumtypes.Regulkode;
import be.schaubroeck.lpb.tools.enumtypes.RekenLogStatus;
import be.schaubroeck.lpb.tools.enumtypes.Rekenmodus;
import be.schaubroeck.lpb.tools.jpa.al.WerkgeverPO;
import be.schaubroeck.lpb.tools.jpa.lo.PersoonPO;
import be.schaubroeck.lpb.tools.jpa.lo.RegulAgendaPK;
import be.schaubroeck.lpb.tools.jpa.lo.RegulAgendaPO;
import be.schaubroeck.lpb.tools.jpa.lo.RekenLog2PO;
import be.schaubroeck.lpb.tools.service.OpdrachtService;
import be.schaubroeck.lpb.tools.service.RegulAgendaService;
import be.schaubroeck.lpb.tools.service.RekenLog2Service;
import be.schaubroeck.lpb.tools.util.InitializeAdmin;
import be.schaubroeck.temporal.interval.Eternity;
import be.schaubroeck.temporal.util.TemporalContext;
import lombok.extern.slf4j.Slf4j;
import org.joda.time.LocalDate;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.transaction.annotation.Transactional;

import java.util.List;
import java.util.Map;
import java.util.Objects;
import java.util.Set;
import java.util.function.Function;
import java.util.stream.Collectors;

@Slf4j
@Transactional
public class StandaardRekenenHelpService implements RekenenHelpService {

    @Autowired
    private RegulAgendaService regulAgendaService;
    @Autowired
    private RekenLog2Service rekenLog2Service;
    @Autowired
    private OpdrachtService opdrachtService;

    @Override
    @InitializeAdmin
    public void logFatalException(Admin admin, LocalDate beginDatum, Integer persoonId, Set<Integer> opdrachtNrs, Exception exception) {
        log.error("Fatale fout in admin {} bij rekenen persoonid {}", admin.getId(), persoonId, exception);
        try {
            for (Integer opdrachtNr : opdrachtNrs) {
                Werkgever werkgever = bepaalWerkgever(admin, persoonId, opdrachtNr);
                RegulAgenda regulAgenda = maakRegulAgenda(beginDatum, persoonId, opdrachtNr, werkgever, Regulkode.FATAL_ERROR);
                RegulAgenda bestaand = regulAgendaService.getById(admin, regulAgenda.getId());
                if (bestaand == null) {
                    regulAgendaService.create(admin, regulAgenda);
                }
            }
        } catch (Exception metaException) {
            log.error("Fout bij schrijven naar regulagenda", metaException);
        }
    }

    private Werkgever bepaalWerkgever(Admin admin, Integer persoonId, Integer opdrachtNr) {
        Werkgever werkgever = new WerkgeverPO(0);
        try {
            TemporalContext.getInstance().setActualInterval(new Eternity());
            Opdracht opdracht = opdrachtService.getByPersoonOpdrachtNr(admin, persoonId, opdrachtNr, "werkgever");
            TemporalContext.getInstance().clearActualInterval();
            werkgever = opdracht.getWerkgever();
        } catch (Exception exception) {
            log.error("Fout bij ophalen opdracht voor regulagenda fatale fout", exception);
        }
        return werkgever;
    }

    private RegulAgenda maakRegulAgenda(LocalDate beginDatum, Integer persoonId, Integer opdrachtNr, Werkgever werkgever, Regulkode regulKode) {
        Persoon persoon = new PersoonPO(persoonId);
        RegulAgenda regul = new RegulAgendaPO();
        RegulAgendaPK id = new RegulAgendaPK();
        regul.setId(id);
        regul.setBeginDatum(beginDatum.dayOfMonth().withMinimumValue());
        regul.setEindDatum(beginDatum.dayOfMonth().withMaximumValue());
        regul.setPersoon(persoon);
        regul.setOpdrachtNummer(opdrachtNr);
        regul.setWerkgever(werkgever);
        regul.setRegulStatus(regulKode.getCode());
        regul.setBron(BronAgenda.REKENMOTOR);
        return regul;
    }

    @Override
    @InitializeAdmin
    public void doeRekenLog(
            Admin admin, Integer persoonId, Set<Integer> opdrachtNrs, RekenTijd rekenTijd, Rekenmodus rekenModus,
            RekenLogStatus status, RekenFeedback feedback, String actor) {
        List<RekenLog2> logs = rekenLog2Service.findByPersoonIdBegindatum(admin, persoonId, rekenTijd.beginDatum);
        Map<Integer, RekenLog2> opdrachtNr2LogsMap = logs.stream().collect(Collectors.toMap(RekenLog2::getOpdrachtNr, Function.identity()));
        for (Integer opdrachtNr : opdrachtNrs) {
            RekenLog2 rekenLog = opdrachtNr2LogsMap.get(opdrachtNr);
            if (rekenLog == null) {
                Werkgever werkgever = bepaalWerkgever(admin, persoonId, opdrachtNr);
                rekenLog = maakRekenLog(persoonId, opdrachtNr, werkgever, rekenTijd, rekenModus, status, feedback, actor);
                rekenLog2Service.create(admin, rekenLog);
            } else {
                rekenLog.setRekenModus(rekenModus);
                rekenLog.setLaatstGerekend(rekenTijd.rekenTijdstip);
                rekenLog.setStatus(status);
                rekenLog.setLaatsteActor(actor);
                setRekenLog2Feedback(rekenLog, feedback);
                rekenLog2Service.update(admin, rekenLog);
            }
        }
    }

    @Override
    @InitializeAdmin
    public void verwijderRegulsZonderOverlappendeOpdracht(Admin admin, Integer persoonId) {
        try {
            List<Opdracht> opdrachten = opdrachtService.findByPersoonIdActualFree(admin, persoonId);
            List<RegulAgenda> reguls = regulAgendaService.findByPersoonId(admin, persoonId);
            Map<Integer, Opdracht> opdrachtMap = opdrachten.stream().collect(Collectors.toMap(Opdracht::getOpdrachtnr, Function.identity()));
            List<RegulAgenda> regulsZonderOverlapping = reguls.stream()
                    .filter(regul -> regulZonderOverlappendeOpdracht(opdrachtMap, regul))
                    .collect(Collectors.toList());
            regulAgendaService.delete(admin, regulsZonderOverlapping);
        } catch (Exception exception) {
            log.error("Fout bij het verwijderen uit regulagenda", exception);
        }
    }

    private boolean regulZonderOverlappendeOpdracht(Map<Integer, Opdracht> opdrachten, RegulAgenda regulAgenda) {
        Opdracht opdracht = opdrachten.get(regulAgenda.getOpdrachtNummer());
        return Objects.isNull(opdracht) || !opdracht.getPeriode().overlaps(regulAgenda.getPeriode());
    }

    private RekenLog2 maakRekenLog(
            Integer persoonId, Integer opdrachtNr, Werkgever werkgever, RekenTijd rekenTijd, Rekenmodus rekenModus,
            RekenLogStatus status, RekenFeedback feedback, String actor) {
        RekenLog2 rekenLog = new RekenLog2PO();
        rekenLog.setPersoon(new PersoonPO(persoonId));
        rekenLog.setOpdrachtNr(opdrachtNr);
        rekenLog.setWerkgever(werkgever);
        rekenLog.setBeginDatum(rekenTijd.beginDatum);
        rekenLog.setEindDatum(rekenTijd.eindDatum);
        rekenLog.setRekenModus(rekenModus);
        rekenLog.setLaatstGerekend(rekenTijd.rekenTijdstip);
        rekenLog.setStatus(status);
        rekenLog.setLaatsteActor(actor);
        setRekenLog2Feedback(rekenLog, feedback);
        return rekenLog;
    }

    private void setRekenLog2Feedback(RekenLog2 rekenLog, RekenFeedback feedback) {
        if (feedback != null) {
            rekenLog.setAantalRekenHoofden(feedback.getAantalRekenHoofden());
            rekenLog.setAantalArtikelHoofden(feedback.getAantalArtikelHoofden());
            rekenLog.setAantalRegulAgendas(feedback.getAantalRegulAgendas());
            rekenLog.setAantalArtikelAgendas(feedback.getAantalArtikelAgendas());
            rekenLog.setAantalMaandTotalen(feedback.getAantalMaandtotalen());
            rekenLog.setAantalControleAgendas(feedback.getAantalControleAgendas());
            rekenLog.setHasWachtagenda(feedback.getHasWachtagenda());
        }
    }
}
